    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0-only\n/*\n *  linux/fs/buffer.c\n *\n *  Copyright (C) 1991, 1992, 2002  Linus Torvalds\n */\n\n/*\n * Start bdflush() with kernel_thread not syscall - Paul Gortmaker, 12/95\n *\n * Removed a lot of unnecessary code and simplified things now that\n * the buffer cache isn't our primary cache - Andrew Tridgell 12/96\n *\n * Speed up hash, lru, and free list operations.  Use gfp() for allocating\n * hash table, use SLAB cache for buffer heads. SMP threading.  -DaveM\n *\n * Added 32k buffer block sizes - these are required older ARM systems. - RMK\n *\n * async buffer flushing, 1999 Andrea Arcangeli <andrea@suse.de>\n */\n\n#include <linux/kernel.h>\n#include <linux/sched/signal.h>\n#include <linux/syscalls.h>\n#include <linux/fs.h>\n#include <linux/iomap.h>\n#include <linux/mm.h>\n#include <linux/percpu.h>\n#include <linux/slab.h>\n#include <linux/capability.h>\n#include <linux/blkdev.h>\n#include <linux/blk-crypto.h>\n#include <linux/file.h>\n#include <linux/quotaops.h>\n#include <linux/highmem.h>\n#include <linux/export.h>\n#include <linux/backing-dev.h>\n#include <linux/writeback.h>\n#include <linux/hash.h>\n#include <linux/suspend.h>\n#include <linux/buffer_head.h>\n#include <linux/task_io_accounting_ops.h>\n#include <linux/bio.h>\n#include <linux/cpu.h>\n#include <linux/bitops.h>\n#include <linux/mpage.h>\n#include <linux/bit_spinlock.h>\n#include <linux/pagevec.h>\n#include <linux/sched/mm.h>\n#include <trace/events/block.h>\n#include <linux/fscrypt.h>\n#include <linux/fsverity.h>\n#include <linux/sched/isolation.h>\n\n#include \"internal.h\"\n\nstatic int fsync_buffers_list(spinlock_t *lock, struct list_head *list);\nstatic void submit_bh_wbc(blk_opf_t opf, struct buffer_head *bh,\n\t\t\t  enum rw_hint hint, struct writeback_control *wbc);\n\n#define BH_ENTRY(list) list_entry((list), struct buffer_head, b_assoc_buffers)\n\ninline void touch_buffer(struct buffer_head *bh)\n{\n\ttrace_block_touch_buffer(bh);\n\tfolio_mark_accessed(bh->b_folio);\n}\nEXPORT_SYMBOL(touch_buffer);\n\nvoid __lock_buffer(struct buffer_head *bh)\n{\n\twait_on_bit_lock_io(&bh->b_state, BH_Lock, TASK_UNINTERRUPTIBLE);\n}\nEXPORT_SYMBOL(__lock_buffer);\n\nvoid unlock_buffer(struct buffer_head *bh)\n{\n\tclear_bit_unlock(BH_Lock, &bh->b_state);\n\tsmp_mb__after_atomic();\n\twake_up_bit(&bh->b_state, BH_Lock);\n}\nEXPORT_SYMBOL(unlock_buffer);\n\n/*\n * Returns if the folio has dirty or writeback buffers. If all the buffers\n * are unlocked and clean then the folio_test_dirty information is stale. If\n * any of the buffers are locked, it is assumed they are locked for IO.\n */\nvoid buffer_check_dirty_writeback(struct folio *folio,\n\t\t\t\t     bool *dirty, bool *writeback)\n{\n\tstruct buffer_head *head, *bh;\n\t*dirty = false;\n\t*writeback = false;\n\n\tBUG_ON(!folio_test_locked(folio));\n\n\thead = folio_buffers(folio);\n\tif (!head)\n\t\treturn;\n\n\tif (folio_test_writeback(folio))\n\t\t*writeback = true;\n\n\tbh = head;\n\tdo {\n\t\tif (buffer_locked(bh))\n\t\t\t*writeback = true;\n\n\t\tif (buffer_dirty(bh))\n\t\t\t*dirty = true;\n\n\t\tbh = bh->b_this_page;\n\t} while (bh != head);\n}\n\n/*\n * Block until a buffer comes unlocked.  This doesn't stop it\n * from becoming locked again - you have to lock it yourself\n * if you want to preserve its state.\n */\nvoid __wait_on_buffer(struct buffer_head * bh)\n{\n\twait_on_bit_io(&bh->b_state, BH_Lock, TASK_UNINTERRUPTIBLE);\n}\nEXPORT_SYMBOL(__wait_on_buffer);\n\nstatic void buffer_io_error(struct buffer_head *bh, char *msg)\n{\n\tif (!test_bit(BH_Quiet, &bh->b_state))\n\t\tprintk_ratelimited(KERN_ERR\n\t\t\t\"Buffer I/O error on dev %pg, logical block %llu%s\\n\",\n\t\t\tbh->b_bdev, (unsigned long long)bh->b_blocknr, msg);\n}\n\n/*\n * End-of-IO handler helper function which does not touch the bh after\n * unlocking it.\n * Note: unlock_buffer() sort-of does touch the bh after unlocking it, but\n * a race there is benign: unlock_buffer() only use the bh's address for\n * hashing after unlocking the buffer, so it doesn't actually touch the bh\n * itself.\n */\nstatic void __end_buffer_read_notouch(struct buffer_head *bh, int uptodate)\n{\n\tif (uptodate) {\n\t\tset_buffer_uptodate(bh);\n\t} else {\n\t\t/* This happens, due to failed read-ahead attempts. */\n\t\tclear_buffer_uptodate(bh);\n\t}\n\tunlock_buffer(bh);\n}\n\n/*\n * Default synchronous end-of-IO handler..  Just mark it up-to-date and\n * unlock the buffer.\n */\nvoid end_buffer_read_sync(struct buffer_head *bh, int uptodate)\n{\n\tput_bh(bh);\n\t__end_buffer_read_notouch(bh, uptodate);\n}\nEXPORT_SYMBOL(end_buffer_read_sync);\n\nvoid end_buffer_write_sync(struct buffer_head *bh, int uptodate)\n{\n\tif (uptodate) {\n\t\tset_buffer_uptodate(bh);\n\t} else {\n\t\tbuffer_io_error(bh, \", lost sync page write\");\n\t\tmark_buffer_write_io_error(bh);\n\t\tclear_buffer_uptodate(bh);\n\t}\n\tunlock_buffer(bh);\n\tput_bh(bh);\n}\nEXPORT_SYMBOL(end_buffer_write_sync);\n\nstatic struct buffer_head *\n__find_get_block_slow(struct block_device *bdev, sector_t block, bool atomic)\n{\n\tstruct address_space *bd_mapping = bdev->bd_mapping;\n\tconst int blkbits = bd_mapping->host->i_blkbits;\n\tstruct buffer_head *ret = NULL;\n\tpgoff_t index;\n\tstruct buffer_head *bh;\n\tstruct buffer_head *head;\n\tstruct folio *folio;\n\tint all_mapped = 1;\n\tstatic DEFINE_RATELIMIT_STATE(last_warned, HZ, 1);\n\n\tindex = ((loff_t)block << blkbits) / PAGE_SIZE;\n\tfolio = __filemap_get_folio(bd_mapping, index, FGP_ACCESSED, 0);\n\tif (IS_ERR(folio))\n\t\tgoto out;\n\n\t/*\n\t * Folio lock protects the buffers. Callers that cannot block\n\t * will fallback to serializing vs try_to_free_buffers() via\n\t * the i_private_lock.\n\t */\n\tif (atomic)\n\t\tspin_lock(&bd_mapping->i_private_lock);\n\telse\n\t\tfolio_lock(folio);\n\n\thead = folio_buffers(folio);\n\tif (!head)\n\t\tgoto out_unlock;\n\t/*\n\t * Upon a noref migration, the folio lock serializes here;\n\t * 