    "content": "{"content":"}\n\n/*\n * If folio was marked as dropbehind, then pages should be dropped when writeback\n * completes. Do that now. If we fail, it's likely because of a big folio -\n * just reset dropbehind for that case and latter completions should invalidate.\n */\nvoid folio_end_dropbehind(struct folio *folio)\n{\n\tif (!folio_test_dropbehind(folio))\n\t\treturn;\n\n\t/*\n\t * Hitting !in_task() should not happen off RWF_DONTCACHE writeback,\n\t * but can happen if normal writeback just happens to find dirty folios\n\t * that were created as part of uncached writeback, and that writeback\n\t * would otherwise not need non-IRQ handling. Just skip the\n\t * invalidation in that case.\n\t */\n\tif (in_task() && folio_trylock(folio)) {\n\t\tfilemap_end_dropbehind(folio);\n\t\tfolio_unlock(folio);\n\t}\n}\nEXPORT_SYMBOL_GPL(folio_end_dropbehind);\n\n/**\n * folio_end_writeback_no_dropbehind - End writeback against a folio.\n * @folio: The folio.\n *\n * The folio must actually be under writeback.\n * This call is intended for filesystems that need to defer dropbehind.\n *\n * Context: May be called from process or interrupt context.\n */\nvoid folio_end_writeback_no_dropbehind(struct folio *folio)\n{\n\tVM_BUG_ON_FOLIO(!folio_test_writeback(folio), folio);\n\n\t/*\n\t * folio_test_clear_reclaim() could be used here but it is an\n\t * atomic operation and overkill in this particular case. Failing\n\t * to shuffle a folio marked for immediate reclaim is too mild\n\t * a gain to justify taking an atomic operation penalty at the\n\t * end of every folio writeback.\n\t */\n\tif (folio_test_reclaim(folio)) {\n\t\tfolio_clear_reclaim(folio);\n\t\tfolio_rotate_reclaimable(folio);\n\t}\n\n\tif (__folio_end_writeback(folio))\n\t\tfolio_wake_bit(folio, PG_writeback);\n\n\tacct_reclaim_writeback(folio);\n}\nEXPORT_SYMBOL_GPL(folio_end_writeback_no_dropbehind);\n\n/**\n * folio_end_writeback - End writeback against a folio.\n * @folio: The folio.\n *\n * The folio must actually be under writeback.\n *\n * Context: May be called from process or interrupt context.\n */\nvoid folio_end_writeback(struct folio *folio)\n{\n\tVM_BUG_ON_FOLIO(!folio_test_writeback(folio), folio);\n\n\t/*\n\t * Writeback does not hold a folio reference of its own, relying\n\t * on truncation to wait for the clearing of PG_writeback.\n\t * But here we must make sure that the folio is not freed and\n\t * reused before the folio_wake_bit().\n\t */\n\tfolio_get(folio);\n\tfolio_end_writeback_no_dropbehind(folio);\n\tfolio_end_dropbehind(folio);\n\tfolio_put(folio);\n}\nEXPORT_SYMBOL(folio_end_writeback);\n\n/**\n * __folio_lock - Get a lock on the folio, assuming we need to sleep to get it.\n * @folio: The folio to lock\n */\nvoid __folio_lock(struct folio *folio)\n{\n\tfolio_wait_bit_common(folio, PG_locked, TASK_UNINTERRUPTIBLE,\n\t\t\t\tEXCLUSIVE);\n}\nEXPORT_SYMBOL(__folio_lock);\n\nint __folio_lock_killable(struct folio *folio)\n{\n\treturn folio_wait_bit_common(folio, PG_locked, TASK_KILLABLE,\n\t\t\t\t\tEXCLUSIVE);\n}\nEXPORT_SYMBOL_GPL(__folio_lock_killable);\n\nstatic int __folio_lock_async(struct folio *folio, struct wait_page_queue *wait)\n{\n\tstruct wait_queue_head *q = folio_waitqueue(folio);\n\tint ret;\n\n\twait->folio = folio;\n\twait->bit_nr = PG_locked;\n\n\tspin_lock_irq(&q->lock);\n\t__add_wait_queue_entry_tail(q, &wait->wait);\n\tfolio_set_waiters(folio);\n\tret = !folio_trylock(folio);\n\t/*\n\t * If we were successful now, we know we're still on the\n\t * waitqueue as we're still under the lock. This means it's\n\t * safe to remove and return success, we know the callback\n\t * isn't going to trigger.\n\t */\n\tif (!ret)\n\t\t__remove_wait_queue(q, &wait->wait);\n\telse\n\t\tret = -EIOCBQUEUED;\n\tspin_unlock_irq(&q->lock);\n\treturn ret;\n}\n\n/*\n * Return values:\n * 0 - folio is locked.\n * non-zero - folio is not locked.\n *     mmap_lock or per-VMA lock has been released (mmap_read_unlock() or\n *     vma_end_read()), unless flags had both FAULT_FLAG_ALLOW_RETRY and\n *     FAULT_FLAG_RETRY_NOWAIT set, in which case the lock is still held.\n *\n * If neither ALLOW_RETRY nor KILLABLE are set, will always return 0\n * with the folio locked and the mmap_lock/per-VMA lock is left unperturbed.\n */\nvm_fault_t __folio_lock_or_retry(struct folio *folio, struct vm_fault *vmf)\n{\n\tunsigned int flags = vmf->flags;\n\n\tif (fault_flag_allow_retry_first(flags)) {\n\t\t/*\n\t\t * CAUTION! In this case, mmap_lock/per-VMA lock is not\n\t\t * released even though returning VM_FAULT_RETRY.\n\t\t */\n\t\tif (flags & FAULT_FLAG_RETRY_NOWAIT)\n\t\t\treturn VM_FAULT_RETRY;\n\n\t\trelease_fault_lock(vmf);\n\t\tif (flags & FAULT_FLAG_KILLABLE)\n\t\t\tfolio_wait_locked_killable(folio);\n\t\telse\n\t\t\tfolio_wait_locked(folio);\n\t\treturn VM_FAULT_RETRY;\n\t}\n\tif (flags & FAULT_FLAG_KILLABLE) {\n\t\tbool ret;\n\n\t\tret = __folio_lock_killable(folio);\n\t\tif (ret) {\n\t\t\trelease_fault_lock(vmf);\n\t\t\treturn VM_FAULT_RETRY;\n\t\t}\n\t} else {\n\t\t__folio_lock(folio);\n\t}\n\n\treturn 0;\n}\n\n/**\n * page_cache_next_miss() - Find the next gap in the page cache.\n * @mapping: Mapping.\n * @index: Index.\n * @max_scan: Maximum range to search.\n *\n * Search the range [index, min(index + max_scan - 1, ULONG_MAX)] for the\n * gap with the lowest index.\n *\n * This function may be called under the rcu_read_lock.  However, this will\n * not atomically search a snapshot of the cache at a single point in time.\n * For example, if a gap is created at index 5, then subsequently a gap is\n * created at index 10, page_cache_next_miss covering both indices may\n * return 10 if called under the rcu_read_lock.\n *\n * Return: The index of the gap if found, otherwise an index outside the\n * range specified (in which case 'return - index >= max_scan' will be true).\n * In the rare case of index wrap-around, 0 will be returned.\n */\npgoff_t page_cache_next_miss(struct address_space *mapping,\n\t\t\t     pgoff_t index, unsigned long max_scan)\n{\n\tXA_STATE(xas, &mapping->i_pages, index);\n\tunsigned long nr = max_scan;\n\n\twhile (nr--) {\n\t\tvoid *entry = xas_next(&xas);\n\t\tif (!entry || xa_is_value(entry))\n\t\t\treturn xas.xa_index;\n\t\tif (xas.xa_index == 0)\n\t\t\treturn 0;\n\t}\n\n\treturn index + max_scan;\n}\nEXPORT_SYMBOL(page_cache_next_miss);\n\n/**\n * page_cache_prev_miss() - Find the previous gap in the page cache.\n * @mapping: Mapping.\n * @index: Index.\n * @max_scan: Maximum range to search.\n *\n * Search the range [max(index - max_scan + 1, 0), index] for the\n * gap with the highest index.\n *\n * This function may be called under the rcu_read_lock.  However, this will\n * not atomically search a snapshot of the cache at a single point in time.\n * For example, if a gap is created at index 10, then subsequently a gap is\n * created at index 5, page_cache_prev_miss() covering both indices may\n * return 5 if called under the rcu_read_lock.\n *\n * Return: The index of the gap if found, otherwise an index outside the\n * range specified (in which case 'index - return >= max_scan' will be true).\n * In the rare case of wrap-around, ULONG_MAX will be returned.\n */\npgoff_t page_cache_prev_miss(struct address_space *mapping,\n\t\t\t     pgoff_t index, unsigned long max_scan)\n{\n\tXA_STATE(xas, &mapping->i_pages, index);\n\n\twhile (max_scan--) {\n\t\tvoid *entry = xas_prev(&xas);\n\t\tif (!entry || xa_is_value(entry))\n\t\t\tbreak;\n\t\tif (xas.xa_index == ULONG_MAX)\n\t\t\tbreak;\n\t}\n\n\treturn xas.xa_index;\n}\nEXPORT_SYMBOL(page_cache_prev_miss);\n\n/*\n * Lockless page cache protocol:\n * On the lookup side:\n * 1. Load the folio from i_pages\n * 2. Increment the refcount if it's not zero\n * 3. If the folio is not found by xas_reload(), put the refcount and retry\n *\n * On the removal side:\n * A. Freeze the page (by zeroing the refcount if nobody else has a reference)\n * B. Remove the page from i_pages\n * C. Return the page to the page allocator\n *\n * This means that any page may have its reference count temporarily\n * increased by a speculative page cache (or GUP-fast) lookup as it can\n * be allocated by another user before the RCU grace period expires.\n * Because the refcount temporarily acquired here may end up being the\n * last refcount on the page, any page allocation must be freeable by\n * folio_put().\n */\n\n/*\n * filemap_get_entry - Get a page cache entry.\n * @mapping: the address_space to search\n * @index: The page cache index.\n *\n * Looks up the page cache entry at @mapping & @index.  If it is a folio,\n * it is returned with an increased refcount.  If it is a shadow entry\n * of a previously evicted folio, or a swap entry from shmem/tmpfs,\n * it is returned without further action.\n *\n * Return: The folio, swap or shadow entry, %NULL if nothing is found.\n */\nvoid *filemap_get_entry(struct address_space *mapping, pgoff_t index)\n{\n\tXA_STATE(xas, &mapping->i_pages, index);\n\tstruct folio *folio;\n\n\trcu_read_lock();\nrepeat:\n\txas_reset(&xas);\n\tfolio = xas_load(&xas);\n\tif (xas_retry(&xas, folio))\n\t\tgoto repeat;\n\t/*\n\t * A shadow entry of a recently evicted page, or a swap entry from\n\t * shmem/tmpfs.  Return it without attempting to raise page count.\n\t */\n\tif (!folio || xa_is_value(folio))\n\t\tgoto out;\n\n\tif (!folio_try_get(folio))\n\t\tgoto repeat;\n\n\tif (unlikely(folio != xas_reload(&xas))) {\n\t\tfolio_put(folio);\n\t\tgoto repeat;\n\t}\nout:\n\trcu_read_unlock();\n\n\treturn folio;\n}\n\n/**\n * __filemap_get_folio_mpol - Find and get a reference to a folio.\n * @mapping: The address_space to search.\n * @index: The page index.\n * @fgp_flags: %FGP flags modify how the folio is returned.\n * @gfp: Memory allocation flags to use if %FGP_CREAT is specified.\n * @policy: NUMA memory allocation policy to follow.\n *\n * Looks up the page cache entry at @mapping & @index.\n *\n * If %FGP_LOCK or %FGP_CREAT are specified then the function may sleep even\n * if the %GFP flags specified for %FGP_CREAT are atomic.\n *\n * If this function returns a folio, it is returned with an increased refcount.\n *\n * Return: The found folio or an ERR_PTR() otherwise.\n */\nstruct folio *__filemap_get_folio_mpol(struct address_space *mapping,\n\t\tpgoff_t index, fgf_t fgp_flags, gfp_t gfp, struct mempolicy *policy)\n{\n\tstruct folio *folio;\n\nrepeat:\n\tfolio = filemap_get_entry(mapping, index);\n\tif (xa_is_value(folio))\n\t\tfolio = NULL;\n\tif (!folio)\n\t\tgoto no_page;\n\n\tif (fgp_flags & FGP_LOCK) {\n\t\tif (fgp_flags & FGP_NOWAIT) {\n\t\t\tif (!folio_trylock(folio)) {\n\t\t\t\tfolio_put(folio);\n\t\t\t\treturn ERR_PTR(-EAGAIN);\n\t\t\t}\n\t\t} else {\n\t\t\tfolio_lock(folio);\n\t\t}\n\n\t\t/* Has the page been truncated? */\n\t\tif (unlikely(folio->mapping != mapping)) {\n\t\t\tfolio_unlock(folio);\n\t\t\tfolio_put(folio);\n\t\t\tgoto repeat;\n\t\t}\n\t\tVM_BUG_ON_FOLIO(!folio_contains(folio, index), folio);\n\t}\n\n\tif (fgp_flags & FGP_ACCESSED)\n\t\tfolio_mark_accessed(folio);\n\telse if (fgp_flags & FGP_WRITE) {\n\t\t/* Clear idle flag for buffer write */\n\t\tif (folio_test_idle(folio))\n\t\t\tfolio_clear_idle(folio);\n\t}\n\n\tif (fgp_flags & FGP_STABLE)\n\t\tfolio_wait_stable(folio);\nno_page:\n\tif (!folio && (fgp_flags & FGP_CREAT)) {\n\t\tunsigned int min_order = mapping_min_folio_order(mapping);\n\t\tunsigned int order = max(min_order, FGF_GET_ORDER(fgp_flags));\n\t\tint err;\n\t\tindex = mapping_align_index(mapping, index);\n\n\t\tif ((fgp_flags & FGP_WRITE) && mapping_can_writeback(mapping))\n\t\t\tgfp |= __GFP_WRITE;\n\t\tif (fgp_flags & FGP_NOFS)\n\t\t\tgfp &= ~__GFP_FS;\n\t\tif (fgp_flags & FGP_NOWAIT) {\n\t\t\tgfp &= ~GFP_KERNEL;\n\t\t\tgfp |= GFP_NOWAIT;\n\t\t}\n\t\tif (WARN_ON_ONCE(!(fgp_flags & (FGP_LOCK | FGP_FOR_MMAP))))\n\t\t\tfgp_flags |= FGP_LOCK;\n\n\t\tif (order > mapping_max_folio_order(mapping))\n\t\t\torder = mapping_max_folio_order(mapping);\n\t\t/* If we're not aligned, allocate a smaller folio */\n\t\tif (index & ((1UL << order) - 1))\n\t\t\torder = __ffs(index);\n\n\t\tdo {\n\t\t\tgfp_t alloc_gfp = gfp;\n\n\t\t\terr = -ENOMEM;\n\t\t\tif (order > min_order)\n\t\t\t\talloc_gfp |= __GFP_NORETRY | __GFP_NOWARN;\n\t\t\tfolio = filemap_alloc_folio(alloc_gfp, order, policy);\n\t\t\tif (!folio)\n\t\t\t\tcontinue;\n\n\n... [Diff truncated. Dropped 2332 lines] ...\n\n\t\tcond_resched();\n\n\t\tif (unlikely(status == 0)) {\n\t\t\t/*\n\t\t\t * A short copy made ->write_end() reject the\n\t\t\t * thing entirely.  Might be memory poisoning\n\t\t\t * halfway through, might be a race with munmap,\n\t\t\t * might be severe memory pressure.\n\t\t\t */\n\t\t\tif (chunk > PAGE_SIZE)\n\t\t\t\tchunk /= 2;\n\t\t\tif (copied) {\n\t\t\t\tbytes = copied;\n\t\t\t\tgoto retry;\n\t\t\t}\n\n\t\t\t/*\n\t\t\t * 'folio' is now unlocked and faults on it can be\n\t\t\t * handled. Ensure forward progress by trying to\n\t\t\t * fault it in now.\n\t\t\t */\n\t\t\tif (fault_in_iov_iter_readable(i, bytes) == bytes) {\n\t\t\t\tstatus = -EFAULT;\n\t\t\t\tbreak;\n\t\t\t}\n\t\t} else {\n\t\t\tpos += status;\n\t\t\twritten += status;\n\t\t}\n\t} while (iov_iter_count(i));\n\n\tif (!written)\n\t\treturn status;\n\tiocb->ki_pos += written;\n\treturn written;\n}\nEXPORT_SYMBOL(generic_perform_write);\n\n/**\n * __generic_file_write_iter - write data to a file\n * @iocb:\tIO state structure (file, offset, etc.)\n * @from:\tiov_iter with data to write\n *\n * This function does all the work needed for actually writing data to a\n * file. It does all basic checks, removes SUID from the file, updates\n * modification times and calls proper subroutines depending on whether we\n * do direct IO or a standard buffered write.\n *\n * It expects i_rwsem to be grabbed unless we work on a block device or similar\n * object which does not need locking at all.\n *\n * This function does *not* take care of syncing data in case of O_SYNC write.\n * A caller has to handle it. This is mainly due to the fact that we want to\n * avoid syncing under i_rwsem.\n *\n * Return:\n * * number of bytes written, even for truncated writes\n * * negative error code if no data has been written at all\n */\nssize_t __generic_file_write_iter(struct kiocb *iocb, struct iov_iter *from)\n{\n\tstruct file *file = iocb->ki_filp;\n\tstruct address_space *mapping = file->f_mapping;\n\tstruct inode *inode = mapping->host;\n\tssize_t ret;\n\n\tret = file_remove_privs(file);\n\tif (ret)\n\t\treturn ret;\n\n\tret = file_update_time(file);\n\tif (ret)\n\t\treturn ret;\n\n\tif (iocb->ki_flags & IOCB_DIRECT) {\n\t\tret = generic_file_direct_write(iocb, from);\n\t\t/*\n\t\t * If the write stopped short of completing, fall back to\n\t\t * buffered writes.  Some filesystems do this for writes to\n\t\t * holes, for example.  For DAX files, a buffered write will\n\t\t * not succeed (even if it did, DAX does not handle dirty\n\t\t * page-cache pages correctly).\n\t\t */\n\t\tif (ret < 0 || !iov_iter_count(from) || IS_DAX(inode))\n\t\t\treturn ret;\n\t\treturn direct_write_fallback(iocb, from, ret,\n\t\t\t\tgeneric_perform_write(iocb, from));\n\t}\n\n\treturn generic_perform_write(iocb, from);\n}\nEXPORT_SYMBOL(__generic_file_write_iter);\n\n/**\n * generic_file_write_iter - write data to a file\n * @iocb:\tIO state structure\n * @from:\tiov_iter with data to write\n *\n * This is a wrapper around __generic_file_write_iter() to be used by most\n * filesystems. It takes care of syncing the file in case of O_SYNC file\n * and acquires i_rwsem as needed.\n * Return:\n * * negative error code if no data has been written at all of\n *   vfs_fsync_range() failed for a synchronous write\n * * number of bytes written, even for truncated writes\n */\nssize_t generic_file_write_iter(struct kiocb *iocb, struct iov_iter *from)\n{\n\tstruct file *file = iocb->ki_filp;\n\tstruct inode *inode = file->f_mapping->host;\n\tssize_t ret;\n\n\tinode_lock(inode);\n\tret = generic_write_checks(iocb, from);\n\tif (ret > 0)\n\t\tret = __generic_file_write_iter(iocb, from);\n\tinode_unlock(inode);\n\n\tif (ret > 0)\n\t\tret = generic_write_sync(iocb, ret);\n\treturn ret;\n}\nEXPORT_SYMBOL(generic_file_write_iter);\n\n/**\n * filemap_release_folio() - Release fs-specific metadata on a folio.\n * @folio: The folio which the kernel is trying to free.\n * @gfp: Memory allocation flags (and I/O mode).\n *\n * The address_space is trying to release any data attached to a folio\n * (presumably at folio->private).\n *\n * This will also be called if the private_2 flag is set on a page,\n * indicating that the folio has other metadata associated with it.\n *\n * The @gfp argument specifies whether I/O may be performed to release\n * this page (__GFP_IO), and whether the call may block\n * (__GFP_RECLAIM & __GFP_FS).\n *\n * Return: %true if the release was successful, otherwise %false.\n */\nbool filemap_release_folio(struct folio *folio, gfp_t gfp)\n{\n\tstruct address_space * const mapping = folio->mapping;\n\n\tBUG_ON(!folio_test_locked(folio));\n\tif (!folio_needs_release(folio))\n\t\treturn true;\n\tif (folio_test_writeback(folio))\n\t\treturn false;\n\n\tif (mapping && mapping->a_ops->release_folio)\n\t\treturn mapping->a_ops->release_folio(folio, gfp);\n\treturn try_to_free_buffers(folio);\n}\nEXPORT_SYMBOL(filemap_release_folio);\n\n/**\n * filemap_invalidate_inode - Invalidate/forcibly write back a range of an inode's pagecache\n * @inode: The inode to flush\n * @flush: Set to write back rather than simply invalidate.\n * @start: First byte to in range.\n * @end: Last byte in range (inclusive), or LLONG_MAX for everything from start\n *       onwards.\n *\n * Invalidate all the folios on an inode that contribute to the specified\n * range, possibly writing them back first.  Whilst the operation is\n * undertaken, the invalidate lock is held to prevent new folios from being\n * installed.\n */\nint filemap_invalidate_inode(struct inode *inode, bool flush,\n\t\t\t     loff_t start, loff_t end)\n{\