    "content": "{"content":"EXPORT_SYMBOL(block_is_partially_uptodate);\n\n/*\n * Generic \"read_folio\" function for block devices that have the normal\n * get_block functionality. This is most of the block device filesystems.\n * Reads the folio asynchronously --- the unlock_buffer() and\n * set/clear_buffer_uptodate() functions propagate buffer state into the\n * folio once IO has completed.\n */\nint block_read_full_folio(struct folio *folio, get_block_t *get_block)\n{\n\tstruct inode *inode = folio->mapping->host;\n\tsector_t iblock, lblock;\n\tstruct buffer_head *bh, *head, *prev = NULL;\n\tsize_t blocksize;\n\tint fully_mapped = 1;\n\tbool page_error = false;\n\tloff_t limit = i_size_read(inode);\n\n\t/* This is needed for ext4. */\n\tif (IS_ENABLED(CONFIG_FS_VERITY) && IS_VERITY(inode))\n\t\tlimit = inode->i_sb->s_maxbytes;\n\n\thead = folio_create_buffers(folio, inode, 0);\n\tblocksize = head->b_size;\n\n\tiblock = div_u64(folio_pos(folio), blocksize);\n\tlblock = div_u64(limit + blocksize - 1, blocksize);\n\tbh = head;\n\n\tdo {\n\t\tif (buffer_uptodate(bh))\n\t\t\tcontinue;\n\n\t\tif (!buffer_mapped(bh)) {\n\t\t\tint err = 0;\n\n\t\t\tfully_mapped = 0;\n\t\t\tif (iblock < lblock) {\n\t\t\t\tWARN_ON(bh->b_size != blocksize);\n\t\t\t\terr = get_block(inode, iblock, bh, 0);\n\t\t\t\tif (err)\n\t\t\t\t\tpage_error = true;\n\t\t\t}\n\t\t\tif (!buffer_mapped(bh)) {\n\t\t\t\tfolio_zero_range(folio, bh_offset(bh),\n\t\t\t\t\t\tblocksize);\n\t\t\t\tif (!err)\n\t\t\t\t\tset_buffer_uptodate(bh);\n\t\t\t\tcontinue;\n\t\t\t}\n\t\t\t/*\n\t\t\t * get_block() might have updated the buffer\n\t\t\t * synchronously\n\t\t\t */\n\t\t\tif (buffer_uptodate(bh))\n\t\t\t\tcontinue;\n\t\t}\n\n\t\tlock_buffer(bh);\n\t\tif (buffer_uptodate(bh)) {\n\t\t\tunlock_buffer(bh);\n\t\t\tcontinue;\n\t\t}\n\n\t\tmark_buffer_async_read(bh);\n\t\tif (prev)\n\t\t\tsubmit_bh(REQ_OP_READ, prev);\n\t\tprev = bh;\n\t} while (iblock++, (bh = bh->b_this_page) != head);\n\n\tif (fully_mapped)\n\t\tfolio_set_mappedtodisk(folio);\n\n\t/*\n\t * All buffers are uptodate or get_block() returned an error\n\t * when trying to map them - we must finish the read because\n\t * end_buffer_async_read() will never be called on any buffer\n\t * in this folio.\n\t */\n\tif (prev)\n\t\tsubmit_bh(REQ_OP_READ, prev);\n\telse\n\t\tfolio_end_read(folio, !page_error);\n\n\treturn 0;\n}\nEXPORT_SYMBOL(block_read_full_folio);\n\n/* utility function for filesystems that need to do work on expanding\n * truncates.  Uses filesystem pagecache writes to allow the filesystem to\n * deal with the hole.  \n */\nint generic_cont_expand_simple(struct inode *inode, loff_t size)\n{\n\tstruct address_space *mapping = inode->i_mapping;\n\tconst struct address_space_operations *aops = mapping->a_ops;\n\tstruct folio *folio;\n\tvoid *fsdata = NULL;\n\tint err;\n\n\terr = inode_newsize_ok(inode, size);\n\tif (err)\n\t\tgoto out;\n\n\terr = aops->write_begin(NULL, mapping, size, 0, &folio, &fsdata);\n\tif (err)\n\t\tgoto out;\n\n\terr = aops->write_end(NULL, mapping, size, 0, 0, folio, fsdata);\n\tBUG_ON(err > 0);\n\nout:\n\treturn err;\n}\nEXPORT_SYMBOL(generic_cont_expand_simple);\n\nstatic int cont_expand_zero(const struct kiocb *iocb,\n\t\t\t    struct address_space *mapping,\n\t\t\t    loff_t pos, loff_t *bytes)\n{\n\tstruct inode *inode = mapping->host;\n\tconst struct address_space_operations *aops = mapping->a_ops;\n\tunsigned int blocksize = i_blocksize(inode);\n\tstruct folio *folio;\n\tvoid *fsdata = NULL;\n\tpgoff_t index, curidx;\n\tloff_t curpos;\n\tunsigned zerofrom, offset, len;\n\tint err = 0;\n\n\tindex = pos >> PAGE_SHIFT;\n\toffset = pos & ~PAGE_MASK;\n\n\twhile (index > (curidx = (curpos = *bytes)>>PAGE_SHIFT)) {\n\t\tzerofrom = curpos & ~PAGE_MASK;\n\t\tif (zerofrom & (blocksize-1)) {\n\t\t\t*bytes |= (blocksize-1);\n\t\t\t(*bytes)++;\n\t\t}\n\t\tlen = PAGE_SIZE - zerofrom;\n\n\t\terr = aops->write_begin(iocb, mapping, curpos, len,\n\t\t\t\t\t    &folio, &fsdata);\n\t\tif (err)\n\t\t\tgoto out;\n\t\tfolio_zero_range(folio, offset_in_folio(folio, curpos), len);\n\t\terr = aops->write_end(iocb, mapping, curpos, len, len,\n\t\t\t\t\t\tfolio, fsdata);\n\t\tif (err < 0)\n\t\t\tgoto out;\n\t\tBUG_ON(err != len);\n\t\terr = 0;\n\n\t\tbalance_dirty_pages_ratelimited(mapping);\n\n\t\tif (fatal_signal_pending(current)) {\n\t\t\terr = -EINTR;\n\t\t\tgoto out;\n\t\t}\n\t}\n\n\t/* page covers the boundary, find the boundary offset */\n\tif (index == curidx) {\n\t\tzerofrom = curpos & ~PAGE_MASK;\n\t\t/* if we will expand the thing last block will be filled */\n\t\tif (offset <= zerofrom) {\n\t\t\tgoto out;\n\t\t}\n\t\tif (zerofrom & (blocksize-1)) {\n\t\t\t*bytes |= (blocksize-1);\n\t\t\t(*bytes)++;\n\t\t}\n\t\tlen = offset - zerofrom;\n\n\t\terr = aops->write_begin(iocb, mapping, curpos, len,\n\t\t\t\t\t    &folio, &fsdata);\n\t\tif (err)\n\t\t\tgoto out;\n\t\tfolio_zero_range(folio, offset_in_folio(folio, curpos), len);\n\t\terr = aops->write_end(iocb, mapping, curpos, len, len,\n\t\t\t\t\t\tfolio, fsdata);\n\t\tif (err < 0)\n\t\t\tgoto out;\n\t\tBUG_ON(err != len);\n\t\terr = 0;\n\t}\nout:\n\treturn err;\n}\n\n/*\n * For moronic filesystems that do not allow holes in file.\n * We may have to extend the file.\n */\nint cont_write_begin(const struct kiocb *iocb, struct address_space *mapping,\n\t\t     loff_t pos, unsigned len, struct folio **foliop,\n\t\t     void **fsdata, get_block_t *get_block, loff_t *bytes)\n{\n\tstruct inode *inode = mapping->host;\n\tunsigned int blocksize = i_blocksize(inode);\n\tunsigned int zerofrom;\n\tint err;\n\n\terr = cont_expand_zero(iocb, mapping, pos, bytes);\n\tif (err)\n\t\treturn err;\n\n\tzerofrom = *bytes & ~PAGE_MASK;\n\tif (pos+len > *bytes && zerofrom & (blocksize-1)) {\n\t\t*bytes |= (blocksize-1);\n\t\t(*bytes)++;\n\t}\n\n\treturn block_write_begin_iocb(iocb, mapping, pos, len, foliop,\n\t\t\t\t     get_block);\n}\nEXPORT_SYMBOL(cont_write_begin);\n\n/*\n * block_page_mkwrite() is not allowed to change the file size as it gets\n * called from a page fault handler when a page is first dirtied. Hence we must\n * be careful to check for EOF conditions here. We set the page up correctly\n * for a written page which means we get ENOSPC checking when writing into\n * holes and correct delalloc and unwritten extent mapping on filesystems that\n * support these features.\n *\n * We are not allowed to take the i_rwsem here so we have to play games to\n * protect against truncate races as the page could now be beyond EOF.  Because\n * truncate writes the inode size before removing pages, once we have the\n * page lock we can determine safely if the page is beyond EOF. If it is not\n * beyond EOF, then the page is guaranteed safe against truncation until we\n * unlock the page.\n *\n * Direct callers of this function should protect against filesystem freezing\n * using sb_start_pagefault() - sb_end_pagefault() functions.\n */\nint block_page_mkwrite(struct vm_area_struct *vma, struct vm_fault *vmf,\n\t\t\t get_block_t get_block)\n{\n\tstruct folio *folio = page_folio(vmf->page);\n\tstruct inode *inode = file_inode(vma->vm_file);\n\tunsigned long end;\n\tloff_t size;\n\tint ret;\n\n\tfolio_lock(folio);\n\tsize = i_size_read(inode);\n\tif ((folio->mapping != inode->i_mapping) ||\n\t    (folio_pos(folio) >= size)) {\n\t\t/* We overload EFAULT to mean page got truncated */\n\t\tret = -EFAULT;\n\t\tgoto out_unlock;\n\t}\n\n\tend = folio_size(folio);\n\t/* folio is wholly or partially inside EOF */\n\tif (folio_pos(folio) + end > size)\n\t\tend = size - folio_pos(folio);\n\n\tret = __block_write_begin_int(folio, 0, end, get_block, NULL);\n\tif (unlikely(ret))\n\t\tgoto out_unlock;\n\n\tblock_commit_write(folio, 0, end);\n\n\tfolio_mark_dirty(folio);\n\tfolio_wait_stable(folio);\n\treturn 0;\nout_unlock:\n\tfolio_unlock(folio);\n\treturn ret;\n}\nEXPORT_SYMBOL(block_page_mkwrite);\n\nint block_truncate_page(struct address_space *mapping,\n\t\t\tloff_t from, get_block_t *get_block)\n{\n\tpgoff_t index = from >> PAGE_SHIFT;\n\tunsigned blocksize;\n\tsector_t iblock;\n\tsize_t offset, length, pos;\n\tstruct inode *inode = mapping->host;\n\tstruct folio *folio;\n\tstruct buffer_head *bh;\n\tint err = 0;\n\n\tblocksize = i_blocksize(inode);\n\tlength = from & (blocksize - 1);\n\n\t/* Block boundary? Nothing to do */\n\tif (!length)\n\t\treturn 0;\n\n\tlength = blocksize - length;\n\tiblock = ((loff_t)index * PAGE_SIZE) >> inode->i_blkbits;\n\n\tfolio = filemap_grab_folio(mapping, index);\n\tif (IS_ERR(folio))\n\t\treturn PTR_ERR(folio);\n\n\tbh = folio_buffers(folio);\n\tif (!bh)\n\t\tbh = create_empty_buffers(folio, blocksize, 0);\n\n\t/* Find the buffer that contains \"offset\" */\n\toffset = offset_in_folio(folio, from);\n\tpos = blocksize;\n\twhile (offset >= pos) {\n\t\tbh = bh->b_this_page;\n\t\tiblock++;\n\t\tpos += blocksize;\n\t}\n\n\tif (!buffer_mapped(bh)) {\n\t\tWARN_ON(bh->b_size != blocksize);\n\t\terr = get_block(inode, iblock, bh, 0);\n\t\tif (err)\n\t\t\tgoto unlock;\n\t\t/* unmapped? It's a hole - nothing to do */\n\t\tif (!buffer_mapped(bh))\n\t\t\tgoto unlock;\n\t}\n\n\t/* Ok, it's mapped. Make sure it's up-to-date */\n\tif (folio_test_uptodate(folio))\n\t\tset_buffer_uptodate(bh);\n\n\tif (!buffer_uptodate(bh) && !buffer_delay(bh) && !buffer_unwritten(bh)) {\n\t\terr = bh_read(bh, 0);\n\t\t/* Uhhuh. Read error. Complain and punt. */\n\t\tif (err < 0)\n\t\t\tgoto unlock;\n\t}\n\n\tfolio_zero_range(folio, offset, length);\n\tmark_buffer_dirty(bh);\n\nunlock:\n\tfolio_unlock(folio);\n\tfolio_put(folio);\n\n\treturn err;\n}\nEXPORT_SYMBOL(block_truncate_page);\n\n/*\n * The generic write folio function for buffer-backed address_spaces\n */\nint block_write_full_folio(struct folio *folio, struct writeback_control *wbc,\n\t\tvoid *get_block)\n{\n\tstruct inode * const inode = folio->mapping->host;\n\tloff_t i_size = i_size_read(inode);\n\n\t/* Is the folio fully inside i_size? */\n\tif (folio_next_pos(folio) <= i_size)\n\t\treturn __block_write_full_folio(inode, folio, get_block, wbc);\n\n\t/* Is the folio fully outside i_size? (truncate in progress) */\n\tif (folio_pos(folio) >= i_size) {\n\t\tfolio_unlock(folio);\n\t\treturn 0; /* don't care */\n\t}\n\n\t/*\n\t * The folio straddles i_size.  It must be zeroed out on each and every\n\t * writeback invocation because it may be mmapped.  \"A file is mapped\n\t * in multiples of the page size.  For a file that is not a multiple of\n\t * the page size, the remaining memory is zeroed when mapped, and\n\t * writes to that region are not written out to the file.\"\n\t */\n\tfolio_zero_segment(folio, offset_in_folio(folio, i_size),\n\t\t\tfolio_size(folio));\n\treturn __block_write_full_folio(inode, folio, get_block, wbc);\n}\n\nsector_t generic_block_bmap(struct address_space *mapping, sector_t block,\n\t\t\t    get_block_t *get_block)\n{\n\tstruct inode *inode = mapping->host;\n\tstruct buffer_head tmp = {\n\t\t.b_size = i_blocksize(inode),\n\t};\n\n\tget_block(inode, block, &tmp, 0);\n\treturn tmp.b_blocknr;\n}\nEXPORT_SYMBOL(generic_block_bmap);\n\nstatic void end_bio_bh_io_sync(struct bio *bio)\n{\n\tstruct buffer_head *bh = bio->bi_private;\n\n\tif (unlikely(bio_flagged(bio, BIO_QUIET)))\n\t\tset_bit(BH_Quiet, &bh->b_state);\n\n\tbh->b_end_io(bh, !bio->bi_status);\n\tbio_put(bio);\n}\n\nstatic void submit_bh_wbc(blk_opf_t opf, struct buffer_head *bh,\n\t\t\t  enum rw_hint write_hint,\n\t\t\t  struct writeback_control *wbc)\n{\n\tconst enum req_op op = opf & REQ_OP_MASK;\n\tstruct bio *bio;\n\n\tBUG_ON(!buffer_locked(bh));\n\tBUG_ON(!buffer_mapped(bh));\n\tBUG_ON(!bh->b_end_io);\n\tBUG_ON(buffer_delay(bh));\n\tBUG_ON(buffer_unwritten(bh));\n\n\t/*\n\t * Only clear out a write error when rewriting\n\t */\n\tif (test_set_buffer_req(bh) && (op == REQ_OP_WRITE))\n\t\tclear_buffer_write_io_error(bh);\n\n\tif (buffer_meta(bh))\n\t\topf |= REQ_META;\n\tif (buffer_prio(bh))\n\t\topf |= REQ_PRIO;\n\n\tbio = bio_alloc(bh->b_bdev, 1, opf, GFP_NOIO);\n\n\tif (folio_test_dropbehind(bh->b_folio))\n\t\tbio_set_flag(bio, BIO_COMPLETE_IN_TASK);\n\n\tfscrypt_set_bio_crypt_ctx_bh(bio, bh, GFP_NOIO);\n\n\tbio->bi_iter.bi_sector = bh->b_blocknr * (bh->b_size >> 9);\n\tbio->bi_write_hint = write_hint;\n\n\tbio_add_folio_nofail(bio, bh->b_folio, bh->b_size, bh_offset(bh));\n\n\tbio->bi_end_io = end_bio_bh_io_sync;\n\tbio->bi_private = bh;\n\n\t/* Take care of bh's that straddle the end of the device */\n\tguard_bio_eod(bio);\n\n\tif (wbc) {\n\t\twbc_init_bio(wbc, bio);\n\t\twbc_account_cgroup_owner(wbc, bh->b_folio, bh->b_size);\n\t}\n\n\tblk_crypto_submit_bio(bio);\n}\n\nvoid submit_bh(blk_opf_t opf, struct buffer_head *bh)\n{\n\tsubmit_bh_wbc(opf, bh, WRITE_LIFE_NOT_SET, NULL);\n}\nEXPORT_SYMBOL(submit_bh);\n\nvoid write_dirty_buffer(struct buffer_head *bh, blk_opf_t op_flags)\n{\n\tlock_buffer(bh);\n\tif (!test_clear_buffer_dirty(bh)) {\n\t\tunlock_buffer(bh);\n\t\treturn;\n\t}\n\tbh->b_end_io = end_buffer_write_sync;\n\tget_bh(bh);\n\tsubmit_bh(REQ_OP_WRITE | op_flags, bh);\n}\nEXPORT_SYMBOL(write_dirty_buffer);\n\n/*\n * For a data-integrity writeout, we need to wait upon any in-progress I/O\n * and then start new I/O and then wait upon it.  The caller must have a ref on\n * the buffer_head.\n */\nint __sync_dirty_buffer(struct buffer_head *bh, blk_opf_t op_flags)\n{\n\tWARN_ON(atomic_read(&bh->b_count) < 1);\n\tlock_buffer(bh);\n\tif (test_clear_buffer_dirty(bh)) {\n\t\t/*\n\t\t * The bh should be mapped, but it might not be if the\n\t\t * device was hot-removed. Not much we can do but fail the I/O.\n\t\t */\n\t\tif (!buffer_mapped(bh)) {\n\t\t\tunlock_buffer(bh);\n\t\t\treturn -EIO;\n\t\t}\n\n\t\tget_bh(bh);\n\t\tbh->b_end_io = end_buffer_write_sync;\n\t\tsubmit_bh(REQ_OP_WRITE | op_flags, bh);\n\t\twait_on_buffer(bh);\n\t\tif (!buffer_uptodate(bh))\n\t\t\treturn -EIO;\n\t} else {\n\t\tunlock_buffer(bh);\n\t}\n\treturn 0;\n}\nEXPORT_SYMBOL(__sync_dirty_buffer);\n\nint sync_dirty_buffer(struct buffer_head *bh)\n{\n\treturn __sync_dirty_buffer(bh, REQ_SYNC);\n}\nEXPORT_SYMBOL(sync_dirty_buffer);\n\nstatic inline int buffer_busy(struct buffer_head *bh)\n{\n\treturn atomic_read(&bh->b_count) |\n\t\t(bh->b_state & ((1 << BH_Dirty) | (1 << BH_Lock)));\n}\n\nstatic bool\ndrop_buffers(struct folio *folio, struct buffer_head **buffers_to_free)\n{\n\tstruct buffer_head *head = folio_buffers(folio);\n\tstruct buffer_head *bh;\n\n\tbh = head;\n\tdo {\n\t\tif (buffer_busy(bh))\n\t\t\tgoto failed;\n\t\tbh = bh->b_this_page;\n\t} while (bh != head);\n\n\tdo {\n\t\tstruct buffer_head *next = bh->b_this_page;\n\n\t\tif (bh->b_assoc_map)\n\t\t\t__remove_assoc_queue(bh);\n\t\tbh = next;\n\t} while (bh != head);\n\t*buffers_to_free = head;\n\tfolio_detach_private(folio);\n\treturn true;\nfailed:\n\treturn false;\n}\n\n/**\n * try_to_free_buffers - Release buffers attached to this folio.\n * @folio: The folio.\n *\n * If any buffers are in use (dirty, under writeback, elevated refcount),\n * no buffers will be freed.\n *\n * If the folio is dirty but all the buffers are clean then we need to\n * be sure to mark the folio clean as well.  This is because the folio\n * may be against a block device, and a later reattachment of buffers\n * to a dirty folio will set *all* buffers dirty.  Which would corrupt\n * filesystem data on the same device.\n *\n * The same applies to regular filesystem folios: if all the buffers are\n * clean then we set the folio clean and proceed.  To do that, we require\n * total exclusion from block_dirty_folio().  That is obtained with\n * i_private_lock.\n *\n * Exclusion against try_to_free_buffers may be obtained by either\n * locking the folio or by holding its mapping's i_private_lock.\n *\n * Context: Process context.  @folio must be locked.  Will not sleep.\n * Return: true if all buffers attached to this folio were freed.\n */\nbool try_to_free_buffers(struct folio *folio)\n{\n\tstruct address_space * const mapping = folio->mapping;\n\tstruct buffer_head *buffers_to_free = NULL;\n\tbool ret = 0;\n\n\tBUG_ON(!folio_test_locked(folio));\n\tif (folio_test_writeback(folio))\n\t\treturn false;\n\n\t/* Misconfigured folio check */\n\tif (WARN_ON_ONCE(!folio_buffers(folio)))\n\t\treturn true;\n\n\tif (mapping == NULL) {\t\t/* can this still happen? */\n\t\tret = drop_buffers(folio, &buffers_to_free);\n\t\tgoto out;\n\t}\n\n\tspin_lock(&mapping->i_private_lock);\n\tret = drop_buffers(folio, &buffers_to_free);\n\n\t/*\n\t * If the filesystem writes its buffers by hand (eg ext3)\n\t * then we can have clean buffers against a dirty folio.  We\n\t * clean the folio here; otherwise the VM will never notice\n\t * that the filesystem did any IO at all.\n\t *\n\t * Also, during truncate, discard_buffer will have marked all\n\t * the folio's buffers clean.  We discover that here and clean\n\t * the folio also.\n\t *\n\t * i_private_lock must be held over this entire operation in order\n\t * to synchronise against block_dirty_folio and prevent the\n\t * dirty bit from being lost.\n\t */\n\tif (ret)\n\t\tfolio_cancel_dirty(folio);\n\tspin_unlock(&mapping->i_private_lock);\nout:\n\tif (buffers_to_free) {\n\t\tstruct buffer_head *bh = buffers_to_free;\n\n\t\tdo {\n\t\t\tstruct buffer_head *next = bh->b_this_page;\n\t\t\tfree_buffer_head(bh);\n\t\t\tbh = next;\n\t\t} while (bh != buffers_to_free);\n\t}\n\treturn ret;\n}\nEXPORT_SYMBOL(try_to_free_buffers);\n\n/*\n * Buffer-head allocation\n */\nstatic struct kmem_cache *bh_cachep __ro_after_init;\n\n/*\n * Once the number of bh's in the machine exceeds this level, we start\n * stripping them in writeback.\n */\nstatic unsigned long max_buffer_heads __ro_after_init;\n\nint buffer_heads_over_limit;\n\nstruct bh_accounting {\n\tint nr;\t\t\t/* Number of live bh's */\n\tint ratelimit;\t\t/* Limit cacheline bouncing */\n};\n\nstatic DEFINE_PER_CPU(struct bh_accounting, bh_accounting) = {0, 0};\n\nstatic void recalc_bh_state(void)\n{\n\tint i;\n\tint tot = 0;\n\n\tif (__this_cpu_inc_return(bh_accounting.ratelimit) - 1 < 4096)\n\t\treturn;\n\t__this_cpu_write(bh_accounting.ratelimit, 0);\n\tfor_each_online_cpu(i)\n\t\ttot += per_cpu(bh_accounting, i).nr;\n\tbuffer_heads_over_limit = (tot > max_buffer_heads);\n}\n\nstruct buffer_head *alloc_buffer_head(gfp_t gfp_flags)\n{\n\tstruct buffer_head *ret = kmem_cache_zalloc(bh_cachep, gfp_flags);\n\tif (ret) {\n\t\tINIT_LIST_HEAD(&ret->b_assoc_buffers);\n\t\tspin_lock_init(&ret->b_uptodate_lock);\n\t\tpreempt_disable();\n\t\t__this_cpu_inc(bh_accounting.nr);\n\t\trecalc_bh_state();\n\t\tpreempt_enable();\n\t}\n\treturn ret;\n}\nEXPORT_SYMBOL(alloc_buffer_head);\n\nvoid free_buffer_head(struct buffer_head *bh)\n{\n\tBUG_ON(!list_empty(&bh->b_assoc_buffers));\n\tkmem_cache_free(bh_cachep, bh);\n\tpreempt_disable();\n\t__this_cpu_dec(bh_accounting.nr);\n\trecalc_bh_state();\n\tpreempt_enable();\n}\nEXPORT_SYMBOL(free_buffer_head);\n\nstatic int buffer_exit_cpu_dead(unsigned int cpu)\n{\n\tint i;\n\tstruct bh_lru *b = &per_cpu(bh_lrus, cpu);\n\n\tfor (i = 0; i < BH_LRU_SIZE; i++) {\n\t\tbrelse(b->bhs[i]);\n\t\tb->bhs[i] = NULL;\n\t}\n\tthis_cpu_add(bh_accounting.nr, per_cpu(bh_accounting, cpu).nr);\n\tper_cpu(bh_accounting, cpu).nr = 0;\n\treturn 0;\n}\n\n/**\n * bh_uptodate_or_lock - Test whether the buffer is uptodate\n * @bh: struct buffer_head\n *\n * Return true if the buffer is up-to-date and false,\n * with the buffer locked, if not.\n */\nint bh_uptodate_or_lock(struct buffer_head *bh)\n{\n\tif (!buffer_uptodate(bh)) {\n\t\tlock_buffer(bh);\n\t\tif (!buffer_uptodate(bh))\n\t\t\treturn 0;\n\t\tunlock_buffer(bh);\n\t}\n\treturn 1;\n}\nEXPORT_SYMBOL(bh_uptodate_or_lock);\n\n/**\n * __bh_read - Submit read for a locked buffer\n * @bh: struct buffer_head\n * @op_flags: appending REQ_OP_* flags besides REQ_OP_READ\n * @wait: wait until reading finish\n *\n * Returns zero on success or don't wait, and -EIO on error.\n */\nint __bh_read(struct buffer_head *bh, blk_opf_t op_flags, bool wait)\n{\n\tint ret = 0;\n\n\tBUG_ON(!buffer_locked(bh